'use client';

import { useState } from 'react';
import { Download, FileSpreadsheet, FileText, File } from 'lucide-react';
import TimetableGrid from '@/components/TimetableGrid';
import { useSession } from '@/hooks/useSession';
import type { TimetableAssignment } from '@/lib/types';

const EXPORT_FORMATS = [
  { format: 'xlsx', label: 'Excel', icon: FileSpreadsheet },
  { format: 'pdf', label: 'PDF', icon: FileText },
  { format: 'docx', label: 'Word', icon: File },
  { format: 'md', label: 'Markdown', icon: FileText },
];

export default function ResultsPage() {
  const { timetable, schoolData } = useSession();
  const [selectedClass, setSelectedClass] = useState('');

  const assignments: TimetableAssignment[] =
    (timetable as Record<string, unknown>)?.assignments as TimetableAssignment[] || [];
  const days: string[] =
    (timetable as Record<string, unknown>)?.days as string[] ||
    (schoolData as Record<string, unknown>)?.days as string[] ||
    ['lundi', 'mardi', 'mercredi', 'jeudi', 'vendredi'];
  const solveTime = (timetable as Record<string, unknown>)?.solve_time as number || 0;

  const classes = [...new Set(assignments.map((a) => a.school_class))].sort();

  const hasTimetable = assignments.length > 0;

  return (
    <div className="p-8 max-w-7xl mx-auto">
      {/* ── Header ───────────────────────────────────── */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">
            Résultats
          </h1>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
            {hasTimetable
              ? `${assignments.length} cours planifiés en ${solveTime.toFixed(1)}s`
              : 'Aucun emploi du temps généré. Lancez le solveur depuis l\'espace de travail.'}
          </p>
        </div>

        {hasTimetable && (
          <div className="flex gap-2">
            {EXPORT_FORMATS.map((f) => (
              <button
                key={f.format}
                className="inline-flex items-center gap-1.5 px-3 py-2 text-xs font-medium rounded-lg border border-gray-200 dark:border-gray-700 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-900 transition-colors"
                title={`Exporter en ${f.label}`}
              >
                <f.icon size={14} />
                {f.label}
              </button>
            ))}
          </div>
        )}
      </div>

      {!hasTimetable ? (
        /* ── Empty state ──────────────────────────────── */
        <div className="flex flex-col items-center justify-center py-32 text-center">
          <div className="w-16 h-16 rounded-2xl bg-gray-100 dark:bg-gray-800 flex items-center justify-center mb-4">
            <Download size={24} className="text-gray-400" />
          </div>
          <h2 className="text-lg font-semibold text-gray-700 dark:text-gray-300 mb-2">
            Pas encore de résultats
          </h2>
          <p className="text-sm text-gray-400 dark:text-gray-500 max-w-md">
            Configurez votre école dans l&apos;espace de travail, puis lancez la
            génération pour voir l&apos;emploi du temps ici.
          </p>
        </div>
      ) : (
        /* ── Timetable view ───────────────────────────── */
        <div className="space-y-6">
          {/* Class selector */}
          <div className="flex items-center gap-3">
            <label className="text-sm font-medium text-gray-600 dark:text-gray-400">
              Classe :
            </label>
            <div className="flex flex-wrap gap-2">
              {classes.map((c) => (
                <button
                  key={c}
                  onClick={() => setSelectedClass(c)}
                  className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
                    selectedClass === c
                      ? 'bg-teal-600 text-white shadow-md shadow-teal-500/20'
                      : 'bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700'
                  }`}
                >
                  {c}
                </button>
              ))}
            </div>
          </div>

          {/* Grid */}
          <div className="bg-white dark:bg-gray-900 rounded-2xl border border-gray-100 dark:border-gray-800 shadow-sm overflow-hidden p-4">
            <TimetableGrid
              assignments={assignments}
              days={days}
              selectedClass={selectedClass || classes[0] || ''}
            />
          </div>
        </div>
      )}
    </div>
  );
}
