'use client';

import type { TimetableAssignment } from '@/lib/types';

interface Props {
  assignments: TimetableAssignment[];
  days: string[];
  selectedClass: string;
}

function timeToRow(t: string): number {
  const [h, m] = t.split(':').map(Number);
  return (h - 7) * 2 + Math.floor(m / 30);
}

export default function TimetableGrid({ assignments, days, selectedClass }: Props) {
  const filtered = assignments.filter((a) => a.school_class === selectedClass);
  const hours = [
    '07:00','07:30','08:00','08:30','09:00','09:30','10:00','10:30',
    '11:00','11:30','12:00','12:30','13:00','13:30','14:00','14:30',
    '15:00','15:30','16:00','16:30','17:00',
  ];

  if (!filtered.length) {
    return (
      <div className="flex items-center justify-center h-64 text-gray-400 dark:text-gray-600 text-sm">
        Sélectionnez une classe pour afficher son emploi du temps
      </div>
    );
  }

  return (
    <div className="overflow-x-auto">
      <div
        className="grid min-w-[700px]"
        style={{
          gridTemplateColumns: `64px repeat(${days.length}, 1fr)`,
          gridTemplateRows: `40px repeat(${hours.length}, 28px)`,
        }}
      >
        {/* Header row */}
        <div className="bg-gray-50 dark:bg-gray-900 border-b border-r border-gray-100 dark:border-gray-800" />
        {days.map((d) => (
          <div
            key={d}
            className="bg-gray-50 dark:bg-gray-900 border-b border-r border-gray-100 dark:border-gray-800 flex items-center justify-center text-[12px] font-medium text-gray-500 dark:text-gray-400 capitalize"
          >
            {d}
          </div>
        ))}

        {/* Time rows */}
        {hours.map((h) => (
          <div
            key={h}
            className="border-b border-r border-gray-100 dark:border-gray-800 flex items-center justify-end pr-2 text-[10px] text-gray-400 dark:text-gray-600"
            style={{ gridColumn: 1 }}
          >
            {h}
          </div>
        ))}

        {/* Empty cells */}
        {hours.map((h, hi) =>
          days.map((d, di) => (
            <div
              key={`${h}-${d}`}
              className="border-b border-r border-gray-50 dark:border-gray-900"
              style={{ gridColumn: di + 2, gridRow: hi + 2 }}
            />
          )),
        )}

        {/* Assignments */}
        {filtered.map((a, i) => {
          const col = days.indexOf(a.day) + 2;
          const rowStart = timeToRow(a.start_time) + 2;
          const rowEnd = timeToRow(a.end_time) + 2;
          if (col < 2) return null;

          return (
            <div
              key={i}
              className="rounded-lg mx-0.5 px-2 py-1 text-[11px] leading-tight overflow-hidden border border-white/30 shadow-sm flex flex-col justify-center"
              style={{
                gridColumn: col,
                gridRow: `${rowStart} / ${rowEnd}`,
                backgroundColor: a.color || '#E2E8F0',
                color: '#1e293b',
              }}
            >
              <span className="font-semibold truncate">{a.subject}</span>
              <span className="truncate opacity-70">{a.teacher}</span>
              {a.room && (
                <span className="truncate opacity-50 text-[10px]">{a.room}</span>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}
